<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>WastedToken Mint — Physical Proof of Internet History</title>
<style>
  :root{
    --ink:#0b0d0e;
    --paper:#e8e2d4;
    --muted:#9b978b;
    --line:rgba(232,226,212,.16);
    --acid:#d6ff4b;
    --copper:#b66c3c;
  }
  *{box-sizing:border-box}
  html{scroll-behavior:smooth}
  body{
    margin:0;background:var(--ink);color:var(--paper);
    font-family:Arial,Helvetica,sans-serif;
    letter-spacing:.02em;
  }
  header{
    height:76px;padding:0 5vw;display:flex;align-items:center;
    justify-content:space-between;border-bottom:1px solid var(--line);
    position:relative;z-index:3;background:rgba(11,13,14,.9);
  }
  .brand{display:flex;align-items:center;gap:13px;font-weight:800;letter-spacing:.14em;font-size:13px}
  .brand-mark{width:28px;height:28px;border:2px solid var(--acid);border-radius:50%;display:grid;place-items:center;color:var(--acid);font-size:12px}
  nav{display:flex;gap:30px;font-size:11px;text-transform:uppercase;letter-spacing:.16em}
  nav a{color:var(--muted);text-decoration:none} nav a:hover{color:var(--acid)}
  .hero{
    min-height:calc(100vh - 76px);display:grid;grid-template-columns:1fr 1fr;
    align-items:center;padding:5vw;gap:4vw;overflow:hidden;
  }
  .hero-copy{max-width:560px}
  .eyebrow{color:var(--acid);font-size:11px;text-transform:uppercase;letter-spacing:.28em;margin-bottom:23px}
  h1{font-size:clamp(48px,7vw,105px);line-height:.86;letter-spacing:-.075em;margin:0 0 28px;font-weight:900}
  h1 span{display:block;color:transparent;-webkit-text-stroke:1px var(--paper)}
  .hero-copy p{font-size:17px;line-height:1.6;color:#b4afa2;max-width:450px}
  .hero-cta{display:inline-flex;align-items:center;gap:18px;margin-top:24px;color:var(--ink);background:var(--acid);padding:15px 20px;font-size:11px;font-weight:bold;text-transform:uppercase;letter-spacing:.16em;text-decoration:none}
  .hero-cta:after{content:"↗";font-size:18px}
  .hero-stage{height:min( sixtyvh, 690px);height:min(68vh,690px);min-height:400px;display:grid;place-items:center;position:relative}
  #coin-hero{width:100%;height:100%;display:block}
  .stage-label{position:absolute;bottom:3%;left:50%;transform:translateX(-50%);white-space:nowrap;color:#77756e;font-size:10px;text-transform:uppercase;letter-spacing:.22em}
  section{padding:110px 5vw}
  .section-head{display:flex;justify-content:space-between;align-items:end;border-bottom:1px solid var(--line);padding-bottom:25px;margin-bottom:38px}
  .section-head h2{font-size:clamp(32px,5vw,64px);letter-spacing:-.06em;margin:0}
  .section-head p{max-width:390px;color:var(--muted);font-size:13px;line-height:1.6;margin:0}
  .about{background:#131617;display:grid;grid-template-columns:1fr 1fr;gap:10vw}
  .about h2{font-size:clamp(40px,6vw,84px);line-height:.9;letter-spacing:-.07em;margin:0}
  .about h2 em{font-style:normal;color:var(--acid)}
  .about-copy{color:#b7b2a7;line-height:1.8;font-size:15px;max-width:510px}
  .about-copy strong{color:var(--paper)}
  .facts{display:grid;grid-template-columns:repeat(3,1fr);gap:16px;margin-top:42px}
  .fact{border-top:1px solid #40433d;padding-top:13px;color:var(--muted);font-size:10px;text-transform:uppercase;letter-spacing:.13em}
  .fact b{display:block;color:var(--paper);font-size:24px;letter-spacing:-.04em;margin-bottom:6px}
  .collection{background:var(--ink)}
  .grid{display:grid;grid-template-columns:repeat(4,1fr);gap:18px}
  .edition{background:#141718;border:1px solid #292c29;padding:13px;position:relative;min-width:0}
  .edition-canvas{width:100%;height:230px;display:block;background:#101212}
  .edition-info{padding:17px 3px 5px;display:flex;justify-content:space-between;align-items:end;gap:8px}
  .edition-name{font-size:16px;font-weight:bold;letter-spacing:.08em;text-transform:uppercase}
  .edition-meta{color:var(--muted);font-size:10px;text-transform:uppercase;letter-spacing:.11em;margin-top:6px}
  .state{font-size:9px;text-align:right;color:var(--acid);letter-spacing:.1em;line-height:1.4}
  .sold .state{color:#e5765f}.next .state{color:#b3b2ad}
  button.buy{margin-top:18px;width:100%;border:1px solid var(--acid);background:transparent;color:var(--acid);padding:12px;text-transform:uppercase;letter-spacing:.16em;font-size:10px;cursor:pointer}
  button.buy:hover{background:var(--acid);color:var(--ink)}
  .sold:after,.next:after{position:absolute;top:22px;right:22px;padding:6px 8px;font-size:9px;letter-spacing:.13em;background:#e5765f;color:#160e0b;content:"SOLD OUT"}
  .next:after{content:"NEXT SEASON";background:#bdbbb0}
  footer{padding:28px 5vw;color:#686961;border-top:1px solid var(--line);display:flex;justify-content:space-between;font-size:10px;text-transform:uppercase;letter-spacing:.14em}
  @media(max-width:850px){
    nav{display:none}.hero{grid-template-columns:1fr;padding-top:45px}.hero-stage{order:-1;height:55vh;min-height:330px}
    .about{grid-template-columns:1fr;gap:40px}.grid{grid-template-columns:repeat(2,1fr)}
  }
  @media(max-width:520px){section{padding:75px 5vw}.grid{grid-template-columns:1fr}.edition-canvas{height:260px}.facts{gap:8px}.fact b{font-size:19px}}
</style>
</head>
<body>
<header>
  <div class="brand"><div class="brand-mark">W</div> WASTEDTOKEN MINT</div>
  <nav><a href="#about">The mint</a><a href="#collection">Editions</a><a href="#collection">Acquire</a></nav>
</header>

<main>
  <section class="hero">
    <div class="hero-copy">
      <div class="eyebrow">Physical proof // Series 01</div>
      <h1>Make it<br><span>count.</span></h1>
      <p>WastedToken Mint turns the internet's most gloriously pointless achievements into objects with weight, edge, and permanence.</p>
      <a class="hero-cta" href="#collection">Explore the drop</a>
    </div>
    <div class="hero-stage">
      <canvas id="coin-hero"></canvas>
      <div class="stage-label">Rotate to inspect // minted in small numbers</div>
    </div>
  </section>

  <section class="about" id="about">
    <div><div class="eyebrow">About the mint</div><h2>For the<br><em>chronically online.</em></h2></div>
    <div class="about-copy">
      <p><strong>WastedToken Mint is an independent maker of collectible challenge coins.</strong> We archive fleeting internet lore in durable metal: a tiny physical receipt for the hours you spent, the rabbit holes you survived, and the lore you were there for.</p>
      <p>Every issue is struck in a limited run, individually inspected, and finished with a reeded edge that feels as good as it looks. No points. No blockchain. Just a very real thing you can put in your pocket.</p>
      <div class="facts"><div class="fact"><b>04</b>metal editions</div><div class="fact"><b>10K</b>token denomination</div><div class="fact"><b>01</b>tiny global cult</div></div>
    </div>
  </section>

  <section class="collection" id="collection">
    <div class="section-head"><h2>Current drop</h2><p>Four finishes. One emblem. Choose your proof of participation before the ledger closes.</p></div>
    <div class="grid">
      <div class="edition" data-edition="bronze" data-state="available">
        <canvas class="edition-canvas"></canvas>
        <div class="edition-info"><div><div class="edition-name">Bronze</div><div class="edition-meta">Warm alloy / 250 struck</div></div><div class="state">Available</div></div>
        <button class="buy">Add to cart</button>
      </div>
      <div class="edition" data-edition="silver" data-state="available">
        <canvas class="edition-canvas"></canvas>
        <div class="edition-info"><div><div class="edition-name">Silver</div><div class="edition-meta">Bright alloy / 100 struck</div></div><div class="state">Available</div></div>
        <button class="buy">Add to cart</button>
      </div>
      <div class="edition sold" data-edition="gold" data-state="sold-out">
        <canvas class="edition-canvas"></canvas>
        <div class="edition-info"><div><div class="edition-name">Gold</div><div class="edition-meta">Auric finish / 25 struck</div></div><div class="state">SOLD OUT</div></div>
      </div>
      <div class="edition next" data-edition="black" data-state="coming-soon">
        <canvas class="edition-canvas"></canvas>
        <div class="edition-info"><div><div class="edition-name">Black</div><div class="edition-meta">Obsidian finish / 100 struck</div></div><div class="state">MINTING<br>SPRING 2026</div></div>
      </div>
    </div>
  </section>
</main>
<footer><span>WastedToken Mint © 2025</span><span>Made for the lore</span></footer>

<script>
(() => {
  const hero = document.getElementById('coin-hero');
  const ctx = hero.getContext('2d');
  let paused=false, raf, last=0, dpr=1;

  function fit(c, context){
    const r=c.getBoundingClientRect(); dpr=Math.min(2,devicePixelRatio||1);
    c.width=Math.max(1,r.width*dpr); c.height=Math.max(1,r.height*dpr);
    context.setTransform(dpr,0,0,dpr,0,0);
    return {w:r.width,h:r.height};
  }
  function metal(ctx,x,y,r,kind,light){
    const colors={
      bronze:['#351c12','#8f4f2e','#d49155','#6f351e'],
      silver:['#343638','#9b9e9c','#f0eee1','#666968'],
      gold:['#553b0b','#b77b18','#ffe28a','#8a5d09'],
      black:['#080a0c','#252b30','#657078','#15191c']
    }[kind]||['#222','#888','#ddd','#555'];
    const g=ctx.createRadialGradient(x-r*.35,y-r*.55,r*.06,x+r*.2,y+r*.2,r*1.15);
    g.addColorStop(0,colors[2]);g.addColorStop(.27,colors[1]);g.addColorStop(.67,colors[0]);g.addColorStop(1,colors[3]);
    ctx.fillStyle=g;ctx.beginPath();ctx.ellipse(x,y,r,r*.98,0,0,Math.PI*2);ctx.fill();
    const shine=ctx.createLinearGradient(x-r+light*r,y-r,x+r+light*r,y+r);
    shine.addColorStop(0,'rgba(255,255,255,0)');shine.addColorStop(.43,'rgba(255,255,255,0)');
    shine.addColorStop(.5,'rgba(255,255,255,.62)');shine.addColorStop(.57,'rgba(255,255,255,0)');
    shine.addColorStop(1,'rgba(255,255,255,0)');
    ctx.save();ctx.globalCompositeOperation='screen';ctx.fillStyle=shine;ctx.beginPath();ctx.ellipse(x,y,r*.98,r*.96,0,0,Math.PI*2);ctx.fill();ctx.restore();
  }
  function coin(c, t, kind='bronze', heroMode=false){
    const q=fit(c,c.getContext('2d')), g=c.getContext('2d'), w=q.w,h=q.h;
    g.clearRect(0,0,w,h);
    const bg=g.createRadialGradient(w*.5,h*.45,2,w*.5,h*.5,Math.max(w,h)*.7);
    bg.addColorStop(0,heroMode?'#202628':'#171b1c');bg.addColorStop(1,'#0b0d0e');g.fillStyle=bg;g.fillRect(0,0,w,h);
    const cx=w/2,cy=h/2, R=Math.min(w,h)*(heroMode?.35:.36);
    const yaw=t*Math.PI*2, pitch=t*Math.PI*2.0+.18;
    const nx=Math.sin(yaw)*Math.cos(pitch), ny=Math.sin(pitch), nz=Math.cos(yaw)*Math.cos(pitch);
    const sx=Math.max(.055,Math.sqrt(Math.max(.003,1-nx*nx)));
    const sy=Math.max(.35,Math.sqrt(Math.max(.08,1-ny*ny)));
    const rx=R*sx, ry=R*sy;
    g.save();g.translate(cx+R*.08,cy+R*.1);g.fillStyle='rgba(0,0,0,.55)';g.filter='blur('+R*.09+'px)';g.beginPath();g.ellipse(0,0,rx*1.04,ry*1.04,0,0,Math.PI*2);g.fill();g.restore();g.filter='none';
    // deep rim
    metal(g,cx,cy,R,kind,(Math.sin(yaw)*.5));
    g.save();g.beginPath();g.ellipse(cx,cy,rx,ry,0,0,Math.PI*2);g.clip();
    // edge ridges, always visible at the compressed side
    g.strokeStyle='rgba(255,235,170,.42)';g.lineWidth=Math.max(1,R*.012);
    for(let i=-18;i<=18;i++){let xx=cx+rx*(i/18);g.beginPath();g.moveTo(xx,cy-ry);g.lineTo(xx,cy+ry);g.stroke()}
    g.restore();
    // face plate only when face has a camera-facing component
    if(Math.abs(nz)>.12){
      g.save();g.beginPath();g.ellipse(cx,cy,rx*.91,ry*.91,0,0,Math.PI*2);g.clip();
      const plate=g.createRadialGradient(cx-rx*.3,cy-ry*.45,1,cx,cy,Math.max(rx,ry));
      const pal={bronze:['#9d542e','#4c2418'],silver:['#e5e1d3','#6e7474'],gold:['#f0bd3e','#78500d'],black:['#4d5960','#111619']}[kind];
      plate.addColorStop(0,pal[0]);plate.addColorStop(.5,pal[1]);plate.addColorStop(1,pal[1]);g.fillStyle=plate;g.fillRect(cx-rx,cy-ry,rx*2,ry*2);
      g.strokeStyle='rgba(255,255,255,.23)';g.lineWidth=Math.max(1,R*.012);g.beginPath();g.ellipse(cx,cy,rx*.86,ry*.86,0,0,Math.PI*2);g.stroke();
      g.fillStyle=nz>0?'rgba(20,13,9,.65)':'rgba(10,12,13,.72)';g.textAlign='center';g.textBaseline='middle';
      if(nz>0){
        g.font='bold '+(R*.18)+'px Arial';g.fillText('W',cx,cy-R*.08);
        g.font='bold '+(R*.075)+'px Arial';g.letterSpacing='3px';g.fillText('WASTED TOKEN',cx,cy+R*.27);
        g.strokeStyle='rgba(255,230,160,.55)';g.lineWidth=R*.018;g.beginPath();g.arc(cx,cy,R*.29,0,Math.PI*2);g.stroke();
        g.font=(R*.045)+'px Arial';g.fillText('MINT • EST. 2025',cx,cy+R*.39);
      }else{
        g.font='bold '+(R*.19)+'px Arial';g.fillText('10,000',cx,cy-R*.05);
        g.font='bold '+(R*.065)+'px Arial';g.fillText('TOKENS',cx,cy+R*.22);
        g.font=(R*.045)+'px Arial';g.fillText('VALID FOR NOTHING',cx,cy+R*.39);
      }
      // moving sharp specular rake over face
      const lx=cx+Math.sin(yaw*1.7+1.2)*rx*.75;
      const hg=g.createLinearGradient(lx-rx*.18,cy-ry,lx+rx*.18,cy+ry);
      hg.addColorStop(0,'rgba(255,255,255,0)');hg.addColorStop(.5,'rgba(255,255,255,.35)');hg.addColorStop(1,'rgba(255,255,255,0)');
      g.globalCompositeOperation='screen';g.fillStyle=hg;g.fillRect(cx-rx,cy-ry,rx*2,ry*2);
      g.restore();
    }
    // outer rim and highlight
    g.strokeStyle='rgba(255,245,210,.6)';g.lineWidth=Math.max(1,R*.025);g.beginPath();g.ellipse(cx,cy,rx,ry,0,0,Math.PI*2);g.stroke();
    g.strokeStyle='rgba(0,0,0,.5)';g.lineWidth=Math.max(1,R*.018);g.beginPath();g.ellipse(cx+R*.015,cy+R*.02,rx*.96,ry*.96,0,0,Math.PI*2);g.stroke();
  }
  function render(t){ coin(hero,t,'bronze',true); }
  function loop(ms){if(!paused){if(!last)last=ms;render(((ms-last)/11000)%1);raf=requestAnimationFrame(loop)}}
  window.demo={canvas:hero,setTime(t){render(((t%1)+1)%1)},pause(){paused=true;cancelAnimationFrame(raf)}};
  const editions=[['bronze',.16],['silver',.31],['gold',.48],['black',.67]];
  document.querySelectorAll('.edition').forEach((el,i)=>coin(el.querySelector('canvas'),editions[i][1],editions[i][0],false));
  window.addEventListener('resize',()=>{render(0);document.querySelectorAll('.edition').forEach((el,i)=>coin(el.querySelector('canvas'),editions[i][1],editions[i][0],false))});
  render(0);raf=requestAnimationFrame(loop);
})();
</script>
</body>
</html>
